# Contains shell command output type specifications

from shellspec import shellspec


@shellspec("ls", [])
def parse_ls(output: str) -> list[str]:
    return output.splitlines()


@shellspec("ls", ["l"])
def parse_ls_long(output: str) -> list[str]:
    return output.splitlines()


@shellspec("wc", ["l"])
def parse_wc_lines(output: str) -> int:
    return int(output.strip().split()[0])


@shellspec("pwd", [])
def parse_pwd(output: str) -> str:
    return output.strip()


@shellspec("whoami", [])
def parse_whoami(output: str) -> str:
    return output.strip()


@shellspec("echo", [])
def parse_echo(output: str) -> str:
    return output.strip()


@shellspec("cat", [])
def parse_cat(output: str) -> str:
    return output


@shellspec("sort", [])
def parse_sort(output: str) -> list[str]:
    return output.splitlines()


@shellspec("uniq", [])
def parse_uniq(output: str) -> list[str]:
    return output.splitlines()


@shellspec("head", [])
def parse_head(output: str) -> list[str]:
    return output.splitlines()


@shellspec("tail", [])
def parse_tail(output: str) -> list[str]:
    return output.splitlines()